var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오느라 고생했다, 레이. 여기가 센트럴 팰리스야.","JPN":"お疲れ様、レイ。ここがセントラルパレスだ。","ENG":"I hope that the trip here wasn’t too difficult for you, Ray. This is Central Palace.","TWN":"路上辛苦了，雷伊，這裡就是聖特羅貝里斯。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"우와…….","JPN":"うわぁ……","ENG":"Whoa...","TWN":"哇……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"여관에 묵던 여행자들에게 들을 때는 반쯤 허풍인 줄 알았는데……. 듣던 것보다 엄청나.","JPN":"旅館に泊まっていた旅の人に聞いた時は、話半分と思っていたけど……聞いていたのより凄いね。","ENG":"I thought that the stories told by the travelers staying at the inn were greatly exaggerated... But this is way more impressive than what I’ve heard.","TWN":"我聽那些住在旅館的旅客們在描述時，還以為他們在吹牛呢……沒想到比我聽到的還誇張。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"평소보다 북적거리는 편이야. 내일이 구원 기사단의 출정식이기 때문이지.","JPN":"いつもよりごった返している方だ。明日、救世騎士団の出征式があるからな。","ENG":"It’s more crowded than it usually is. That’s because the Knights of Redemption are holding their ceremony of war tomorrow.","TWN":"平時沒這麼熱鬧的，是因為明天要舉行救贖騎士團的出征儀式。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"출정식은 구원자와 성녀를 선출하는 자리다. 구경꾼들이 몰릴 수밖에.","JPN":"出征式は救世主と聖女を選ぶ場だ。見物客が押し寄せないはずがない。","ENG":"The Savior and Saintess will be selected during the ceremony. Of course there will be spectators.","TWN":"在出征儀式中會選出救贖者和聖女，因此大家都會聚集到這裡來觀禮。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"구원 기사단이면……. 알렌이랑 버밍엄 부인이 속해 있다던 곳 말이지?","JPN":"救世騎士団といえば……アレンとバーミンガム夫人が所属しているところでしょ？","ENG":"The Knights of Redemption... Aren’t you and Lady Birmingham part of that Order?","TWN":"救贖騎士團……就是你和伯明罕夫人所屬的組織吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"미리 말해두는데 그레이스 앞에서 버밍엄 부인이라고는 부르지 마라.","JPN":"あらかじめ言っておくが、グレースの前ではバーミンガム夫人と呼ぶなよ。","ENG":"Just so you know, don’t call Grace \\"Lady Birmingham\\" in front of her.","TWN":"我先提醒你，在葛瑞絲面前，不要叫她伯明罕夫人。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"나이 들어 보이는 이름이라고 화를 낼 테니까.","JPN":"年取って見える名前だと怒るはずだからな。","ENG":"She’ll get mad, saying that it makes her sound old.","TWN":"她覺得這個稱呼聽起來很老，要是這樣叫她，她會生氣的。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 다녀오도록 하지. 길이 험해서 피곤했을 테니 잠시 쉬고 있어.","JPN":"では、行ってくる。道が悪かったから疲れただろう。少し休んでいなさい。","ENG":"Now, I have somewhere to drop by first. You must be exhausted from the rough trip, so why don’t you take a break?","TWN":"那我先去忙，這一路上長途跋涉，你應該也累了，就先去休息吧。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"응? 알렌, 어디 가려고?","JPN":"え？　アレン、どこに行くの？","ENG":"Huh? Allen, where are you going?","TWN":"嗯？艾倫，你要去哪裡？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네가 황태자 전하를 알현하려면 몇 가지 절차를 거쳐야 해.","JPN":"君が皇太子殿下に謁見するためには、いくつかの手順を踏まなければならない。","ENG":"I must go through a few procedures in order to seek an audience with the Crown Prince His Majesty.","TWN":"在你去見皇太子殿下之前，還需要辦一些流程。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하께서 사소한 일에 신경 쓰는 분은 아니지만, 뭐든 정식 절차를 거쳐야 문제가 생기지 않는 법이다.","JPN":"殿下はささいなことに気を使う方ではないが、何でも正式な手順を踏めば問題が起きないものだ。","ENG":"Although he does not trouble himself with trivial matters, it’s better to go through the official procedures and avoid any trouble.","TWN":"雖然殿下是不拘小節的人，但為免發生什麼問題，還是走正式流程比較保險。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그렇구나…….","JPN":"そうなんだね……","ENG":"I see...","TWN":"喔喔……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어째 갑자기 들뜬 표정이군.","JPN":"なんだか急にそわそわした顔をしているな。","ENG":"You suddenly seem excited for some reason.","TWN":"臉色怎麼突然不太對勁？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"알렌이 항상 이야기하던 황태자 전하를 직접 뵙는 거잖아. 어떤 분일지 조금은 기대돼.","JPN":"アレンがいつも話していた皇太子殿下にじかにお会いするんでしょ。どんな方なのかちょっと楽しみだ。","ENG":"Well, it’s my first time seeing the Crown Prince you always talk about in person. I’m looking forward to seeing what kind of person he is.","TWN":"我終於要親眼見到你常提到的皇太子殿下，有點期待殿下是什麼樣的人呢。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다른 사람들 앞에서는 그렇게 말하지 마라. 불경죄로 처벌 받을 수도 있어.","JPN":"他の人の前ではそんな風に言うなよ。不敬罪で罰せられることもある。","ENG":"Don’t say that in front of other people. You may be punished for disrespecting the crown.","TWN":"在其他人面前千萬不能說這種話，很可能會被冠上大逆不道的罪名而受罰。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"내, 내가 무슨 나쁜 말이라도 했어?","JPN":"ぼ、僕、何か悪い事でも言った？","ENG":"D-did I say something wrong?","TWN":"我…我剛有說什麼不尊敬的話嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 하지만 황실 예법이라는 건 원래 엄격한 거야.","JPN":"いや、でも皇室の礼法というものは元々厳格なんだ。","ENG":"No, but imperial etiquette tends to be strict.","TWN":"沒有，只是皇室禮法本來就很嚴格。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};